#include "biblia.h"

void Biblia::Carregar2Joao(Biblia* b) {
    b->dados[JOAO2].nome = wxT("2 João");

    b->dados[JOAO2].capitulos[1].versos[1] = wxT("O ancião à senhora eleita, e a seus filhos, aos quais eu amo em verdade, e não somente eu, mas também todos os que conhecem a verdade,");
    b->dados[JOAO2].capitulos[1].versos[2] = wxT("por causa da verdade que permanece em nós, e para sempre estará conosco:");
    b->dados[JOAO2].capitulos[1].versos[3] = wxT("Graça, misericórdia, paz, da parte de Deus Pai e da parte de Jesus Cristo, o Filho do Pai, serão conosco em verdade e amor.");
    b->dados[JOAO2].capitulos[1].versos[4] = wxT("Muito me alegro por ter achado alguns de teus filhos andando na verdade, assim como recebemos mandamento do Pai.");
    b->dados[JOAO2].capitulos[1].versos[5] = wxT("E agora, senhora, rogo-te, não como te escrevendo um novo mandamento, mas aquele mesmo que desde o princípio tivemos: que nos amemos uns aos outros.");
    b->dados[JOAO2].capitulos[1].versos[6] = wxT("E o amor é este: que andemos segundo os seus mandamentos. Este é o mandamento, como já desde o princípio ouvistes, para que nele andeis.");
    b->dados[JOAO2].capitulos[1].versos[7] = wxT("Porque já muitos enganadores saíram pelo mundo, os quais não confessam que Jesus Cristo veio em carne. Tal é o enganador e o anticristo.");
    b->dados[JOAO2].capitulos[1].versos[8] = wxT("Olhai por vós mesmos, para que não percais o fruto do nosso trabalho, antes recebeis plena recompensa.");
    b->dados[JOAO2].capitulos[1].versos[9] = wxT("Todo aquele que vai além do ensino de Cristo e não permanece nele, não tem a Deus; quem permanece neste ensino, esse tem tanto ao Pai como ao Filho.");
    b->dados[JOAO2].capitulos[1].versos[10] = wxT("Se alguém vem ter convosco, e não traz este ensino, não o recebais em casa, nem tampouco o saudeis.");
    b->dados[JOAO2].capitulos[1].versos[11] = wxT("Porque quem o saúda participa de suas más obras.");
    b->dados[JOAO2].capitulos[1].versos[12] = wxT("Embora tenha eu muitas coisas para vos escrever, não o quis fazer com papel e tinta; mas espero visitar-vos e falar face a face, para que o nosso gozo seja completo.");
    b->dados[JOAO2].capitulos[1].versos[13] = wxT("Saúdam-te os filhos de tua irmã, a eleita.");

}
